// ===== BEGIN 02-logger.jsx =====
function logMessage(msg, level, tag) {
    if (level === undefined) level = LOG_LEVEL.NORMAL;
    if (tag === undefined) tag = "WORKFLOW";
    if (level > currentLogLevel) return;

    var timestamp = new Date().toLocaleTimeString();
    $.writeln("[" + timestamp + "][" + tag + "] " + msg);
}

// ===== END 02-logger.jsx =====

// ===== BEGIN 03-config-store.jsx =====
function ensureConfigDir() {
    if (!configFolder.exists) {
        configFolder.create();
        logMessage("创建配置目录: " + configFolder.fsName, LOG_LEVEL.NORMAL, "CONFIG");
    }
}

function scanPresetFiles() {
    ensureConfigDir();
    var files = configFolder.getFiles("*.json");
    var presets = [];
    for (var i = 0; i < files.length; i++) {
        var fileName = files[i].name.replace(/\.json$/i, "");
        fileName = decodeUrlString(fileName);
        presets.push({
            name: fileName,
            file: files[i]
        });
    }
    presets.sort(function(a, b) { return a.name < b.name ? -1 : 1; });
    return presets;
}

function getPresetResourcePath(filename) {
    return configFolder.fsName + "/" + filename;
}

function loadPreset(file) {
    if (!file.exists) return null;
    try {
        file.open("r");
        file.encoding = "UTF-8";
        var content = file.read();
        file.close();
        var data = JSON.parse(content);
        return data;
    } catch (e) {
        logMessage("读取预设文件失败: " + file.fsName + " - " + e.message, LOG_LEVEL.ERROR, "CONFIG");
        return null;
    }
}

function savePreset(file, data) {
    try {
        file.encoding = "UTF-8";
        if (file.open("w")) {
            var content = JSON.stringify(data, null, 2);
            file.write(content);
            file.close();
            return true;
        }
    } catch (e) {
        logMessage("保存预设文件失败: " + file.fsName + " - " + e.message, LOG_LEVEL.ERROR, "CONFIG");
    }
    return false;
}

// ===== END 03-config-store.jsx =====

// ===== BEGIN 04-ae-utils.jsx =====
function decodeUrlString(str) {
    try {
        return decodeURIComponent(str);
    } catch (e) {
        return str;
    }
}

function getActiveComp() {
    var item = app.project.activeItem;
    if (item && item instanceof CompItem) {
        return item;
    }
    return null;
}

function getActiveCompName() {
    var comp = getActiveComp();
    if (comp) {
        return decodeUrlString(comp.name);
    }
    return null;
}

function getCompByName(name) {
    for (var i = 1; i <= app.project.items.length; i++) {
        var item = app.project.items[i];
        if (item instanceof CompItem) {
            var itemName = decodeUrlString(item.name);
            if (itemName === name) {
                return item;
            }
        }
    }
    return null;
}

function createComp(name, width, height, frameRate, duration) {
    var pixelAspect = 1.0;
    var comp = app.project.items.addComp(name, width, height, pixelAspect, duration, frameRate);
    logMessage("创建合成: " + name + " (" + width + "x" + height + ", " + frameRate + "fps, " + duration + "s)", LOG_LEVEL.NORMAL, "AE");
    return comp;
}

function calculateFitWidthScale(sourceComp, targetComp) {
    return (targetComp.width / sourceComp.width) * 100;
}

function nestWithScale(sourceComp, targetComp, scaleMode, scalePercent) {
    var layer = targetComp.layers.add(sourceComp);

    if (scaleMode === "fit_width") {
        var scale = calculateFitWidthScale(sourceComp, targetComp);
        layer.scale.setValue([scale, scale, 100]);
        logMessage("嵌套合成 - 自适应宽度缩放: " + scale.toFixed(1) + "%", LOG_LEVEL.NORMAL, "AE");
    } else if (scaleMode === "custom") {
        layer.scale.setValue([scalePercent, scalePercent, 100]);
        logMessage("嵌套合成 - 自定义缩放: " + scalePercent + "%", LOG_LEVEL.NORMAL, "AE");
    }

    layer.label = 1;
}

// ===== END 04-ae-utils.jsx =====

// ===== BEGIN 05a-render-engine.jsx =====
function ensureSequenceTemplate() {
    var templateNames = ["序列帧", "PNG Sequence", "PNG 序列"];
    for (var t = 0; t < templateNames.length; t++) {
        try {
            var tempComp = app.project.items.addComp("__template_check__", 10, 10, 1, 1, 30);
            var rqItem = app.project.renderQueue.items.add(tempComp);
            var om = rqItem.outputModule(1);
            om.applyTemplate(templateNames[t]);
            rqItem.remove();
            try { tempComp.remove(); } catch(e) {}
            logMessage("模板已存在: " + templateNames[t], LOG_LEVEL.VERBOSE, "RENDER");
            return;
        } catch(e) {}
    }

    logMessage("序列帧模板不存在，正在创建...", LOG_LEVEL.NORMAL, "RENDER");
    var tempComp = app.project.items.addComp("__template_create__", 10, 10, 1, 1, 30);
    var rqItem = app.project.renderQueue.items.add(tempComp);
    var om = rqItem.outputModule(1);

    try {
        om.setSetting("Format", "8");
    } catch(e) {
        logMessage("setSetting Format 失败: " + e.toString(), LOG_LEVEL.WARNING, "RENDER");
    }

    om.file = new File(Folder.temp.fsName + "/__template_temp_[#####].png");

    try {
        om.saveToTemplate("序列帧");
        logMessage("模板已创建: 序列帧", LOG_LEVEL.NORMAL, "RENDER");
    } catch(e) {
        logMessage("模板创建失败: " + e.toString(), LOG_LEVEL.WARNING, "RENDER");
    }

    rqItem.remove();
    try { tempComp.remove(); } catch(e) {}
}

function applySequenceTemplate(om) {
    var names = ["序列帧", "PNG 序列", "PNG Sequence", "PNG", "PNG Sequence with Alpha"];
    for (var n = 0; n < names.length; n++) {
        try {
            om.applyTemplate(names[n]);
            var fmt = om.getSetting("Format");
            if (fmt === "8") {
                return true;
            }
        } catch(e) {}
    }
    return false;
}

function renderCompToSequence(comp, projectDir, settings) {
    logMessage("开始渲染: " + comp.name, LOG_LEVEL.NORMAL, "RENDER");

    try {
        var outDir = new Folder(projectDir + "/" + comp.name);
        if (outDir.exists) {
            var oldFiles = outDir.getFiles("*");
            for (var f = 0; f < oldFiles.length; f++) {
                try { oldFiles[f].remove(); } catch(e) {}
            }
        } else {
            outDir.create();
        }

        var rqItem = app.project.renderQueue.items.add(comp);
        var om = rqItem.outputModule(1);

        while (rqItem.outputModules.length > 1) {
            rqItem.outputModule(rqItem.outputModules.length).remove();
        }

        ensureSequenceTemplate();
        var ok = applySequenceTemplate(om);
        if (!ok) {
            logMessage("无法应用序列帧模板，使用默认设置", LOG_LEVEL.WARNING, "RENDER");
        }

        var outFile = new File(outDir.fsName + "/" + comp.name + "_[#####].png");
        om.file = outFile;

        try {
            var fmt = om.getSetting("Format");
            if (fmt !== "8") {
                logMessage("设置文件后Format已变: " + fmt + "，重新应用模板", LOG_LEVEL.WARNING, "RENDER");
                applySequenceTemplate(om);
            }
        } catch(e) {
            logMessage("验证Format失败: " + e.toString(), LOG_LEVEL.WARNING, "RENDER");
        }

        app.project.renderQueue.render();

        if (settings.importBack) {
            importSequenceToComp(comp, outDir);
        }

        rqItem.remove();

        logMessage("渲染完成: " + comp.name, LOG_LEVEL.NORMAL, "RENDER");
        return true;

    } catch (e) {
        logMessage("渲染出错: " + e.message, LOG_LEVEL.ERROR, "RENDER");
        alert("渲染出错: " + e.message);
        return false;
    }
}

function findFirstFileInFolder(folder) {
    if (!folder || !folder.exists) return null;

    var patterns = ["*.png", "*.tga", "*.tif", "*.tiff", "*.jpg", "*.jpeg", "*.exr", "*.bmp", "*.mp4", "*.mov", "*.avi"];
    for (var p = 0; p < patterns.length; p++) {
        var files = folder.getFiles(patterns[p]);
        if (files.length > 0) return files[0];
    }
    return null;
}

function importSequenceToComp(comp, outDir) {
    var firstFile = findFirstFileInFolder(outDir);
    if (!firstFile) {
        logMessage("未找到渲染文件: " + outDir.fsName, LOG_LEVEL.ERROR, "RENDER");
        alert("未找到渲染文件:\n" + outDir.fsName);
        return null;
    }

    var importOpt = new ImportOptions(firstFile);
    importOpt.sequence = true;
    importOpt.forceAlphabetical = true;

    var footage = app.project.importFile(importOpt);
    footage.name = comp.name + "_序列";

    var targetFrameRate = comp.frameRate;
    var actualRate = footage.frameRate;
    logMessage("导入序列帧率: 实际=" + actualRate + "fps, 目标=" + targetFrameRate + "fps", LOG_LEVEL.NORMAL, "RENDER");

    if (Math.abs(actualRate - targetFrameRate) > 0.01) {
        try {
            footage.mainSource.conformFrameRate = targetFrameRate;
            logMessage("帧率已设为: " + targetFrameRate + "fps", LOG_LEVEL.NORMAL, "RENDER");
        } catch(e) {
            logMessage("设置帧率失败: " + e.toString(), LOG_LEVEL.WARNING, "RENDER");
        }
    }

    var layer = comp.layers.add(footage);
    layer.solo = true;
    layer.name = comp.name + "_渲染";
    layer.moveToBeginning();

    logMessage("渲染结果已导入: " + comp.name + " (" + targetFrameRate + "fps)", LOG_LEVEL.NORMAL, "RENDER");
    return footage;
}

function cleanFolder(folder) {
    var count = 0;
    var files = folder.getFiles();
    for (var fi = 0; fi < files.length; fi++) {
        if (files[fi] instanceof Folder) {
            count += cleanFolder(files[fi]);
            files[fi].remove();
        } else {
            files[fi].remove();
        }
        count++;
    }
    return count;
}

function renderSingleFrame(comp, outputFolder, fileName, time) {
    if (time === undefined) time = comp.time;
    if (fileName === undefined) fileName = "高光图";

    var tempFolder = new Folder(Folder.temp.fsName + "/__singleframe_" + String(Math.random()).substr(2, 6));
    if (!tempFolder.exists) tempFolder.create();

    var rqItem = null;
    var result = null;

    try {
        rqItem = app.project.renderQueue.items.add(comp);
        rqItem.timeSpanStart = time;
        rqItem.timeSpanDuration = 1.0 / comp.frameRate;

        while (rqItem.outputModules.length > 1) {
            rqItem.outputModule(rqItem.outputModules.length).remove();
        }

        var om = rqItem.outputModule(1);

        ensureSequenceTemplate();
        var templateOk = false;
        var tplNames = ["序列帧", "PNG 序列", "PNG Sequence"];
        for (var tn = 0; tn < tplNames.length; tn++) {
            try { om.applyTemplate(tplNames[tn]); templateOk = true; break; } catch(e) {}
        }
        if (!templateOk) {
            try { om.setSetting("Format", "8"); } catch(e) {}
        }

        om.file = new File(tempFolder.fsName + "/" + fileName + "_[#####].png");

        app.project.renderQueue.render();

        var renderedFile = findFirstFileInFolder(tempFolder);
        if (renderedFile) {
            if (!outputFolder.exists) outputFolder.create();
            var destFile = new File(outputFolder.fsName + "/" + fileName + ".png");
            renderedFile.copy(destFile.fsName);
            result = destFile;
        }
    } catch(e) {
        logMessage("renderSingleFrame 出错: " + (e.message || e.toString()), LOG_LEVEL.ERROR, "RENDER");
    }

    if (rqItem) { try { rqItem.remove(); } catch(e) {} }
    try { cleanFolder(tempFolder); tempFolder.remove(); } catch(e) {}

    return result;
}

// ===== END 05a-render-engine.jsx =====

// ===== BEGIN 05-workflow-engine.jsx =====
function resolveOutputName(baseName, step) {
    if (step.rename) {
        return String(step.rename).replace("{baseName}", baseName);
    }
    return baseName + (step.suffix || "");
}

function executeWorkflow(sourceComp, baseName, presetFile, activeStates) {
    if (!sourceComp) {
        alert("请先选择一个活动合成！");
        return false;
    }

    if (!baseName) {
        alert("基础名称不能为空！");
        return false;
    }

    var presetData = loadPreset(presetFile);
    if (!presetData || !presetData.steps || presetData.steps.length === 0) {
        alert("预设数据无效或为空！");
        return false;
    }

    app.beginUndoGroup("工作流助手 - " + baseName);

    try {
        logMessage("开始工作流: baseName=" + baseName + ", source=" + sourceComp.name, LOG_LEVEL.NORMAL, "ENGINE");

        var steps = presetData.steps;
        var lastComp = runSteps(sourceComp, baseName, steps, activeStates);

        if (lastComp) {
            lastComp.openInViewer();
            app.endUndoGroup();

            var count = 0;
            var resultMsg = "";
            for (var m = 0; m < steps.length; m++) {
                if (activeStates && !activeStates[m]) continue;
                count++;
                resultMsg += "\n" + count + ". " + resolveOutputName(baseName, steps[m]);
                resultMsg += " (" + steps[m].width + "×" + steps[m].height + ")";
            }
            alert("工作流执行完成！\n共创建 " + count + " 个合成:\n" + resultMsg);
            return true;
        }
        app.endUndoGroup();
        return false;

    } catch (e) {
        app.endUndoGroup();
        alert("工作流执行出错: " + e.message);
        return false;
    }
}

function runSteps(sourceComp, baseName, steps, activeStates) {
    var currentComp = sourceComp;
    var lastComp = null;
    var _customDuration = null;

    for (var j = 0; j < steps.length; j++) {
        if (activeStates && !activeStates[j]) {
            logMessage("跳过步骤 " + (j + 1) + ": " + steps[j].name, LOG_LEVEL.NORMAL, "ENGINE");
            continue;
        }

        var s = steps[j];
        var outputName = resolveOutputName(baseName, s);

        if (getCompByName(outputName)) {
            alert("合成已存在: " + outputName + "\n请先删除或重命名现有合成后再执行。");
            return null;
        }

        logMessage("执行步骤 " + (j + 1) + ": " + outputName, LOG_LEVEL.NORMAL, "ENGINE");

        var durationVal = s.duration;
        if (typeof durationVal === "string" && durationVal === "custom") {
            if (_customDuration === null) {
                var result = prompt("请输入步骤 \"" + s.name + "\" 的时长（秒）:", "5");
                if (result === null || result === "") return null;
                var num = parseFloat(result);
                if (isNaN(num) || num <= 0) {
                    alert("无效的时长！");
                    return null;
                }
                _customDuration = num;
            }
            durationVal = _customDuration;
        }

        var newComp = createComp(outputName, s.width, s.height, s.frameRate, durationVal);
        nestWithScale(currentComp, newComp, s.scaleMode, s.scalePercent);

        if (s.stagger && s.stagger.enabled) {
            var staggerOffset = currentComp.duration;
            var firstLayer = newComp.layer(1);
            for (var k = 1; k < s.stagger.count; k++) {
                var dup = firstLayer.duplicate();
                dup.startTime = k * staggerOffset;
                logMessage("  错层 " + (k + 1) + ": startTime=" + dup.startTime + "s (偏移=" + staggerOffset + "s)", LOG_LEVEL.NORMAL, "ENGINE");
            }
        }

        currentComp = newComp;
        lastComp = newComp;
    }

    return lastComp;
}

function executeSingleStep(sourceComp, baseName, presetFile, stepIndex) {
    if (!sourceComp) {
        alert("请先选择一个活动合成！");
        return false;
    }

    if (!baseName) {
        alert("基础名称不能为空！");
        return false;
    }

    var presetData = loadPreset(presetFile);
    if (!presetData || !presetData.steps || stepIndex >= presetData.steps.length) {
        alert("预设数据无效！");
        return false;
    }

    app.beginUndoGroup("工作流助手 - 单步 " + baseName);

    try {
        logMessage("开始单步: baseName=" + baseName + ", source=" + sourceComp.name + ", step=" + stepIndex, LOG_LEVEL.NORMAL, "ENGINE");

        // 找到此步骤的源合成
        var stepSource = sourceComp;
        if (stepIndex > 0) {
            var prevName = resolveOutputName(baseName, presetData.steps[stepIndex - 1]);
            stepSource = getCompByName(prevName);
            if (!stepSource) {
                alert("前置合成不存在: " + prevName + "\n请先执行前面的步骤。");
                app.endUndoGroup();
                return false;
            }
        }

        var s = presetData.steps[stepIndex];
        var outputName = resolveOutputName(baseName, s);

        if (getCompByName(outputName)) {
            alert("合成已存在: " + outputName + "\n请先删除或重命名现有合成后再执行。");
            app.endUndoGroup();
            return false;
        }

        logMessage("执行步骤 " + stepIndex + ": " + outputName, LOG_LEVEL.NORMAL, "ENGINE");

        var durationVal = s.duration;
        if (typeof durationVal === "string" && durationVal === "custom") {
            var result = prompt("请输入步骤 \"" + s.name + "\" 的时长（秒）:", "5");
            if (result === null || result === "") {
                app.endUndoGroup();
                return false;
            }
            var num = parseFloat(result);
            if (isNaN(num) || num <= 0) {
                alert("无效的时长！");
                app.endUndoGroup();
                return false;
            }
            durationVal = num;
        }

        var newComp = createComp(outputName, s.width, s.height, s.frameRate, durationVal);
        nestWithScale(stepSource, newComp, s.scaleMode, s.scalePercent);

        if (s.stagger && s.stagger.enabled) {
            var staggerOffset = stepSource.duration;
            var firstLayer = newComp.layer(1);
            for (var k = 1; k < s.stagger.count; k++) {
                var dup = firstLayer.duplicate();
                dup.startTime = k * staggerOffset;
            }
        }

        newComp.openInViewer();
        app.endUndoGroup();

        alert("单步执行完成: " + outputName + "\n(" + s.width + "×" + s.height + ", " + s.frameRate + "fps, " + s.duration + "s)");
        return true;

    } catch (e) {
        app.endUndoGroup();
        alert("单步执行出错: " + e.message);
        return false;
    }
}

