    tabOutput.preferredSize.width = 80;

    var tabSync = tabGroup.add("button", undefined, "同步");
    tabSync.preferredSize.width = 80;

    // ================== 内容容器 ==================
    var tabContent = win.add("panel");
    tabContent.orientation = "stack";
    tabContent.alignment = ["fill", "fill"];
