    // --- 整理面板 ---
    var organizeGroup = tabContent.add("group");
    organizeGroup.orientation = "column";
    organizeGroup.alignChildren = ["fill", "top"];
    organizeGroup.alignment = ["fill", "fill"];
    organizeGroup.spacing = 4;
    organizeGroup.margins = 6;

    // 步骤按钮区域
